func formatSourceMeta(item domain.Document) string {
	parts := []string{}
	if item.ParserUsed != "" {
		parts = append(parts, "parser "+item.ParserUsed)
	}
	if item.ChunkCount > 0 {
		parts = append(parts, fmt.Sprintf("%d chunks", item.ChunkCount))
	}
	if item.SizeBytes > 0 {
		parts = append(parts, humanSize(item.SizeBytes))
	}
	if len(parts) == 0 {
		return "Awaiting ingestion details"
	}
	return joinParts(parts)
}

func humanSize(n int64) string {
	const unit = 1024
	if n < unit {
		return fmt.Sprintf("%d B", n)
	}
	div, exp := int64(unit), 0
	for value := n / unit; value >= unit; value /= unit {
		div *= unit
		exp++
	}
	return fmt.Sprintf("%.1f %ciB", float64(n)/float64(div), "KMGTPE"[exp])
}

func joinParts(parts []string) string {
	out := ""
	for i, part := range parts {
		if i > 0 {
			out += " · "
		}
		out += part
	}
	return out
}

